+}
+
+impl Warning {
+    fn preview(content: &str) -> String {
+        let preview: String = content.chars().take(50).collect();
+        if content.len() > 50 {
+            format!("{}...", preview)
+        } else {
+            preview
+        }
+    }
+}
+
+/// Suggestion for user review.
+#[derive(Debug, Clone)]
+pub enum Suggestion {
